import { i18n } from '@fs/zion-locale'
import * as Yup from 'yup'

function isValidISO391Format(inputText) {
  const r1 =
    /(^[a-z]{2,3})([-_]([A-Z]{2}|[0-9]{3,4}))?([-_]([A-Z][a-z]{3}))?([-_]([a-z]{3,8}))?(([-_]x([-_][a-z0-9]{3,8})+))?/
  const match = (inputText || '').match(r1)
  if (match) {
    return match[0] === inputText
  }
  return false
}

export default function getLanguageValidationNEXT({ required, path } = {}) {
  return Yup.object()
    .nullable()
    .required(required || i18n.t('provisional-place.language-required.warning', 'Language is a required field.'))
    .test({
      name: 'language',
      test(value) {
        if (value?.selectedItem?.code && isValidISO391Format(value?.selectedItem?.code)) {
          return true
        }
        if (
          value?.selectedItem?.type === 'INPUT_TEXT_OPTION' &&
          isValidISO391Format(value?.selectedItem?.primaryText)
        ) {
          return true
        }
        return this.createError({
          message: i18n.t('provisional-place.invalid-language.warning', 'Invalid language or BCP-47 code.'),
          path: path || 'lang',
        })
      },
    })
}
